// Turn an inbound email into a reply payload for /inbound.
// Only genuine REPLIES are processed: the original notification has no "Re:" prefix,
// so requiring "Re:" prevents our own outbound email from being stored as the reply.
// NOTE: quote/signature stripping is a heuristic — fine for controlled test accounts.
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const subject = String(j.subject || j.Subject || (j.headers && (j.headers.subject || j.headers.Subject)) || '');

  // Must carry the task tag.
  const m = subject.match(/#([A-Za-z0-9]+)/);
  if (!m) continue;
  const task_id = m[1];

  // Must be a reply, not the original notification. Replies are prefixed "Re:".
  if (!/\bre\s*:/i.test(subject)) continue;

  // Source the body; if only HTML is available, turn it into text, then decode entities.
  let raw = String(j.text || j.textPlain || j.body || j.html || j.textAsHtml || j.snippet || '');
  raw = raw.replace(/<\s*br\s*\/?>/gi, '\n').replace(/<\/(p|div|tr|li|h[1-6])>/gi, '\n').replace(/<[^>]+>/g, '');
  raw = raw.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&');

  // Cut quoted history at the earliest marker (works for multi-line AND single-line snippet bodies).
  const markers = [
    /\n?\s*On\s.+?\swrote:/is,                 // Gmail "On <date> ... wrote:"
    /\n-{2,}\s*Original Message\s*-{2,}/i,      // Outlook
    /\n>/,                                       // quoted line
    /\nFrom:\s/                                  // forwarded header block
  ];
  let idx = raw.length;
  for (const re of markers) { const mm = raw.match(re); if (mm && mm.index < idx) idx = mm.index; }
  let reply = raw.slice(0, idx).replace(/\n{3,}/g, '\n\n').trim();
  reply = reply.split(/\n-- \n/)[0].trim();        // strip signature after a '-- ' delimiter

  const from = j.from || (j.headers && j.headers.from) || '';
  const email = String(from).match(/[\w.+-]+@[\w.-]+\.[\w.-]+/);

  out.push({ json: {
    task_id,
    assignee_email: email ? email[0] : '',
    reply_text: reply,
    received_at: new Date().toISOString()
  }});
}
return out;
